// tests/http/client.test.js
describe('fetchWithRetry', () => {
  test('retries on 429 with exponential backoff', async () => {
    const mockFetch = jest.fn()
      .mockResolvedValueOnce({ status: 429 })
      .mockResolvedValueOnce({ status: 429 })
      .mockResolvedValueOnce({ status: 200, json: () => ({}) });
    global.fetch = mockFetch;
    const result = await fetchWithRetry('http://api.example.com/data');
    expect(result.status).toBe(200);
    expect(mockFetch).toHaveBeenCalledTimes(3);
  });

  test('throws RetryExhaustedError after max retries', async () => {
    const mockFetch = jest.fn().mockRejectedValue(new Error('network error'));
    global.fetch = mockFetch;
    await expect(fetchWithRetry('http://api.example.com/data'))
      .rejects.toThrow(RetryExhaustedError);
    expect(mockFetch).toHaveBeenCalledTimes(3);
  });

  test('MAX_RETRIES is exported and equals 3', () => {
    expect(MAX_RETRIES).toBe(3);
  });

  test('successful request returns response without retry', async () => {
    const mockFetch = jest.fn().mockResolvedValue({ status: 200 });
    global.fetch = mockFetch;
    const result = await fetchWithRetry('http://api.example.com/data');
    expect(result.status).toBe(200);
    expect(mockFetch).toHaveBeenCalledTimes(1);
  });
});
